class Solution:
    def longestSubarray(self, nums):
        mx = max(nums)
        best = 0
        i = 0
        n = len(nums)
        while i < n:
            if nums[i] == mx:
                j = i
                while j < n and nums[j] == mx:
                    j += 1
                best = max(best, j - i)
                i = j
            else:
                i += 1
        return best

