var longestSubarray = function(nums) {
    const mx = Math.max(...nums);
    let best = 0, cur = 0;
    for (const v of nums) {
        if (v === mx) { cur++; if (cur > best) best = cur; }
        else cur = 0;
    }
    return best;
};
